#include<bits/stdc++.h>
using namespace std;
int n,k,a[1005],l,r,mid;
bool check(int f){
	int b=0,c=0;
	for(int i=1;i<=n;i++){
		if(b+a[i]<=f)b+=a[i];
		else b=a[i],c++;
	}
	return c+1<=k;
}
int main(){
	cin>>n;
	for(int i=1;i<=n;i++)
	cin>>a[i],r+=a[i],l=max(l,a[i]);
	cin>>k;
    l--;
	while(l+1<r){
        mid=(l+r)/2;
		if(check(mid))r=mid;
		else l=mid;
	}
	cout<<r;
}
